toggleVideoAnalytics.code:
if (systemType === 'digital' || systemType === 'hybrid') {
  // Show video analytics section
  videoAnalyticsSection.style.display = 'block';
  // Hide N/A option (not logical for digital/hybrid)
  videoAnalyticsNA.style.display = 'none';
} else {
  // Hide video analytics section for analog/none/na
  videoAnalyticsSection.style.display = 'none';
  videoAnalyticsCapabilities.style.display = 'none';
  videoAnalyticsNoDetails.style.display = 'none';
}

toggleVideoAnalyticsDetails.code:
if (answer === 'yes') {
  videoAnalyticsCapabilities.style.display = 'block';
  videoAnalyticsNoDetails.style.display = 'none';
} else if (answer === 'no') {
  videoAnalyticsCapabilities.style.display = 'none';
  videoAnalyticsNoDetails.style.display = 'block';
} else if (answer === 'na') {
  // Hide both sections
  videoAnalyticsCapabilities.style.display = 'none';
  videoAnalyticsNoDetails.style.display = 'none';
}

toggleQuestionDetails.code:
if (answer === 'yes') {
  detailsSection.style.display = 'block';
  noDetailsSection.style.display = 'none';
} else if (answer === 'no') {
  detailsSection.style.display = 'none';
  noDetailsSection.style.display = 'block';
} else if (answer === 'na') {
  detailsSection.style.display = 'none';
  noDetailsSection.style.display = 'none';
}
